// Display priority: evasion / combat-relevant first.
const PRIORITY: KeywordKey[] = ["flying", "menace", "deathtouch", "double_strike", "first_strike", "trample", "lifelink", "vigilance", "reach", "haste", "hexproof", "ward", "indestructible", "defender", "infect"]

// Raw catalog keyword string (cards.keywords) -> our key.
const ALIASES: Record<string, KeywordKey> = {
  flying: "flying",
  reach: "reach",
  deathtouch: "deathtouch",
  lifelink: "lifelink",
  trample: "trample",
  vigilance: "vigilance",
  menace: "menace",
  "first strike": "first_strike",
  "double strike": "double_strike",
  haste: "haste",
  hexproof: "hexproof",
  indestructible: "indestructible",
  defender: "defender",
  ward: "ward",
  infect: "infect",
  toxic: "infect"
}

// Normalise + dedupe + order a card’s catalog keywords to the ones we have icons for.
export function normalizeKeywords(raw?: string[] | null): KeywordKey[] {
  if (!raw) return []
  const seen = new Set<KeywordKey>()
  for (const entry of raw) {
    const key = ALIASES[String(entry).trim().toLowerCase()]
    if (key) seen.add(key)
  }
  return PRIORITY.filter((k) => seen.has(k))
}

export function KeywordIcon({ keyword, size = 12 }: { keyword: KeywordKey; size?: number }) {
  const def = KEYWORD_DEFS[keyword]
  const inner = Math.round(size * 0.72)
  return (
    <span
      title={def.label}
      className="inline-flex shrink-0 items-center justify-center rounded-[3px]"
      style={{ background: def.tone, color: def.ink, width: size, height: size }}
    >
      <svg viewBox="0 0 512 512" width={inner} height={inner} fill="currentColor" aria-hidden>
        <path d={def.path} />
      </svg>
    </span>
  )
}

// A compact row of keyword icons for a creature tile. Shows up to `max`, then “+n”.
export function KeywordIconRow({ keywords, max = 3, size = 12 }: { keywords?: string[] | null; max?: number; size?: number }) {
  const keys = normalizeKeywords(keywords)
  if (keys.length === 0) return null
  const shown = keys.slice(0, max)
  const extra = keys.length - shown.length
  return (
    <span className="flex flex-wrap items-center justify-center gap-0.5">
      {shown.map((k) => (
        <KeywordIcon key={k} keyword={k} size={size} />
      ))}
      {extra > 0 && (
        <span
          className="inline-flex items-center justify-center rounded-[3px] bg-[#2a3040] px-1 text-[7px] font-black text-slate-300"
          style={{ height: size }}
        >
          +{extra}
        </span>
      )}
    </span>
  )
}
